mapper.update:
UPDATE subject SET
name = #{subjectName}, description = #{description}
WHERE subject_id = #{subjectId};

UPDATE lecture SET
	subject_id = #{subjectId}, classroom_id = #{classroomId},
	recruited = #{recruited}, amount = #{amount},
	start_time = #{startTime}, end_time = #{endTime}, day_of_week = #{dayOfWeek},
	start_date = #{startDate}, end_date = #{endDate}
WHERE lecture_id = #{lectureId}

UPDATE teacher_assignment SET
	teacher_id = #{teacherId}
WHERE lecture_id = #{lectureId}

UPDATE classroom SET
	name = #{classroomName}, location = #{location}, capacity = #{capacity}
WHERE classroom_id = #{classroomId}

UPDATE material SET
	lecture_id = #{lectureId}, material_title = #{materialTitle}, total_count = #{totalCount}, used_count = #{usedCount}
WHERE material_id = #{materialId}

UPDATE material_request SET
	status = '처리완료'
WHERE request_id = #{requestId}

UPDATE attendance SET
	status = #{status}
WHERE attendance_id = #{attendanceId}
